      }


      //VALUE COMPARISON SUPPORT
      public override func hashAsValue(into hasher: inout Hasher, visited complexEntities: inout Set<SDAI.ComplexEntity>) {
        super.hashAsValue(into: &hasher, visited: &complexEntities)
      }

      public override func isValueEqual(to rhs: SDAI.PartialEntity, visited comppairs: inout Set<SDAI.ComplexPair>) -> Bool {
        guard let rhs = rhs as? Self else { return false }
        if !super.isValueEqual(to: rhs, visited: &comppairs) { return false }
        return true
      }

      public override func isValueEqualOptionally(to rhs: SDAI.PartialEntity, visited comppairs: inout Set<SDAI.ComplexPair>) -> Bool? {
        guard let rhs = rhs as? Self else { return false }
        var result: Bool? = true
        if let comp = super.isValueEqualOptionally(to: rhs, visited: &comppairs) {
          if !comp { return false }
        }
        else { result = nil }
        return result
      }


      //MARK: WHERE RULES (ENTITY)
      public static func WHERE_wr1(SELF: eDIMENSIONAL_LOCATION.PRef?) -> SDAI.LOGICAL {
        guard let SELF = SELF else { return SDAI.UNKNOWN }
        //
        let _TEMP1 /* eSHAPE_ASPECT_RELATIONSHIP.PRef? */ = SELF.GROUP_REF(eSHAPE_ASPECT_RELATIONSHIP.self)
        let _TEMP2 /* eSHAPE_ASPECT.PRef? */ = _TEMP1?.RELATING_SHAPE_ASPECT
        let _TEMP3 /* eSHAPE_ASPECT_RELATIONSHIP.PRef? */ = SELF.GROUP_REF(eSHAPE_ASPECT_RELATIONSHIP.self)
        let _TEMP4 /* eSHAPE_ASPECT.PRef? */ = _TEMP3?.RELATED_SHAPE_ASPECT
        let _TEMP5 /* SDAI.LOGICAL */ = _TEMP2 .!==. _TEMP4
        return _TEMP5
      }
      public static func WHERE_wr2(SELF: eDIMENSIONAL_LOCATION.PRef?) -> SDAI.LOGICAL {
        guard let SELF = SELF else { return SDAI.UNKNOWN }
        //
        let _TEMP1 /* eSHAPE_ASPECT_RELATIONSHIP.PRef? */ = SELF.GROUP_REF(eSHAPE_ASPECT_RELATIONSHIP.self)
        let _TEMP2 /* eSHAPE_ASPECT.PRef? */ = _TEMP1?.RELATING_SHAPE_ASPECT
        let _TEMP3 /* ePRODUCT_DEFINITION_SHAPE.PRef? */ = _TEMP2?.OF_SHAPE
        let _TEMP4 /* eSHAPE_ASPECT_RELATIONSHIP.PRef? */ = SELF.GROUP_REF(eSHAPE_ASPECT_RELATIONSHIP.self)
        let _TEMP5 /* eSHAPE_ASPECT.PRef? */ = _TEMP4?.RELATED_SHAPE_ASPECT
        let _TEMP6 /* ePRODUCT_DEFINITION_SHAPE.PRef? */ = _TEMP5?.OF_SHAPE
        let _TEMP7 /* SDAI.LOGICAL */ = _TEMP3 .===. _TEMP6
        return _TEMP7
      }
      public static func WHERE_wr3(SELF: eDIMENSIONAL_LOCATION.PRef?) -> SDAI.LOGICAL {
        guard let SELF = SELF else { return SDAI.UNKNOWN }
        //
        let _TEMP1 /* eSHAPE_ASPECT_RELATIONSHIP.PRef? */ = SELF.GROUP_REF(eSHAPE_ASPECT_RELATIONSHIP.self)
        let _TEMP2 /* eSHAPE_ASPECT.PRef? */ = _TEMP1?.RELATING_SHAPE_ASPECT
        let _TEMP3 /* eSHAPE_ASPECT.PRef? */ = _TEMP2?.GROUP_REF(eSHAPE_ASPECT.self)
        let _TEMP4 /* SDAI.LOGICAL? */ = _TEMP3?.PRODUCT_DEFINITIONAL
        let _TEMP5 /* SDAI.LOGICAL */ = _TEMP4 .!=. SDAI.FORCE_OPTIONAL(SDAI.LOGICAL(SDAI.UNKNOWN))
        let _TEMP6 /* eSHAPE_ASPECT_RELATIONSHIP.PRef? */ = SELF.GROUP_REF(eSHAPE_ASPECT_RELATIONSHIP.self)
        let _TEMP7 /* eSHAPE_ASPECT.PRef? */ = _TEMP6?.RELATED_SHAPE_ASPECT
        let _TEMP8 /* eSHAPE_ASPECT.PRef? */ = _TEMP7?.GROUP_REF(eSHAPE_ASPECT.self)
        let _TEMP9 /* SDAI.LOGICAL? */ = _TEMP8?.PRODUCT_DEFINITIONAL
        let _TEMP10 /* SDAI.LOGICAL */ = _TEMP9 .!=. SDAI.FORCE_OPTIONAL(SDAI.LOGICAL(SDAI.UNKNOWN))
        let _TEMP11 /* SDAI.LOGICAL */ = _TEMP5 && _TEMP10
        return _TEMP11
      }

